"use client";

import { Accordion, type AccordionItem } from "@/components/ui/accordion";
import { useState } from "react";

const sampleItems: AccordionItem[] = [
  {
    id: "item-1",
    title: "What is this?",
    description:
      "This is a test page for the Accordion component. It demonstrates the component's functionality with sample content.",
  },
  {
    id: "item-2",
    title: "How does it work?",
    description:
      "Click on the accordion headers to expand and collapse the content. The component supports smooth animations and keyboard navigation.",
  },
  {
    id: "item-3",
    title: "Can I customize it?",
    description:
      "Yes! The Accordion component supports custom classNames for all its parts including root, item, trigger, icon, title, chevron, content, and description.",
  },
  {
    id: "item-4",
    title: "Is it accessible?",
    description:
      "Absolutely. The component uses proper ARIA attributes including aria-expanded, aria-controls, and role='region' for screen reader support.",
  },
];

const disabledItems: AccordionItem[] = [
  {
    id: "enabled-1",
    title: "Enabled Item",
    description: "This item can be expanded and collapsed.",
  },
  {
    id: "disabled-1",
    title: "Disabled Item",
    description: "This item cannot be interacted with.",
    disabled: true,
  },
  {
    id: "enabled-2",
    title: "Another Enabled Item",
    description: "This item can also be expanded and collapsed.",
  },
];

export default function AccordionTestPage() {
  const [value, setValue] = useState<string | null>(null);

  return (
    <main className="min-h-screen px-6 py-16 max-w-2xl mx-auto space-y-12">
      <h1 className="text-3xl font-bold">Accordion Test Page</h1>

      <section className="space-y-4">
        <h2 className="text-xl font-semibold">Default Accordion</h2>
        <p className="text-sm text-muted-foreground">
          Click on the headers to expand/collapse. Only one item can be open at
          a time.
        </p>
        <Accordion items={sampleItems} />
      </section>

      <section className="space-y-4">
        <h2 className="text-xl font-semibold">Controlled Accordion</h2>
        <p className="text-sm text-muted-foreground">
          Current value: <code className="bg-muted px-1 py-0.5 rounded">{value ?? "null"}</code>
        </p>
        <Accordion
          items={sampleItems}
          value={value}
          onValueChange={setValue}
        />
      </section>

      <section className="space-y-4">
        <h2 className="text-xl font-semibold">Disabled Items</h2>
        <Accordion items={disabledItems} />
      </section>

      <section className="space-y-4">
        <h2 className="text-xl font-semibold">With Icons</h2>
        <Accordion
          items={sampleItems.map((item, i) => ({
            ...item,
            icon: (
              <span className="text-lg">
                {["📄", "⚙️", "🎨", "♿"][i]}
              </span>
            ),
          }))}
        />
      </section>
    </main>
  );
}
